import{_ as p,c as t,b as o,a as s,d as a,e as l,r as c,o as i}from"./app-CvT2DUHU.js";const u={},r={href:"https://github.com/coolclaws/deerflow-book",target:"_blank",rel:"noopener noreferrer"};function d(k,n){const e=c("ExternalLinkIcon");return i(),t("div",null,[n[2]||(n[2]=o(`<h1 id="第-21-章-配置体系全解" tabindex="-1"><a class="header-anchor" href="#第-21-章-配置体系全解"><span>第 21 章　配置体系全解</span></a></h1><p>DeerFlow 的配置体系由三层文件组成：<code>config.yaml</code> 负责核心应用设置，<code>extensions_config.json</code> 管理 MCP 服务器与技能状态，<code>.env</code> 文件提供敏感凭据。三者职责分明、互相配合，共同构成了一套灵活而安全的配置架构。</p><h2 id="_21-1-配置加载流程" tabindex="-1"><a class="header-anchor" href="#_21-1-配置加载流程"><span>21.1 配置加载流程</span></a></h2><p>应用启动时，<code>AppConfig.from_file()</code> 按如下优先级定位 <code>config.yaml</code>：</p><ol><li>显式传入的 <code>config_path</code> 参数；</li><li>环境变量 <code>DEER_FLOW_CONFIG_PATH</code> 指向的路径；</li><li>当前工作目录下的 <code>config.yaml</code>，不存在则回退到父目录。</li></ol><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token comment"># backend/src/config/app_config.py</span></span>
<span class="line"><span class="token decorator annotation punctuation">@classmethod</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">resolve_config_path</span><span class="token punctuation">(</span>cls<span class="token punctuation">,</span> config_path<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> Path<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> config_path<span class="token punctuation">:</span></span>
<span class="line">        path <span class="token operator">=</span> Path<span class="token punctuation">(</span>config_path<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token keyword">not</span> Path<span class="token punctuation">.</span>exists<span class="token punctuation">(</span>path<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">            <span class="token keyword">raise</span> FileNotFoundError<span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span> path</span>
<span class="line">    <span class="token keyword">elif</span> os<span class="token punctuation">.</span>getenv<span class="token punctuation">(</span><span class="token string">&quot;DEER_FLOW_CONFIG_PATH&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        path <span class="token operator">=</span> Path<span class="token punctuation">(</span>os<span class="token punctuation">.</span>getenv<span class="token punctuation">(</span><span class="token string">&quot;DEER_FLOW_CONFIG_PATH&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token keyword">else</span><span class="token punctuation">:</span></span>
<span class="line">        path <span class="token operator">=</span> Path<span class="token punctuation">(</span>os<span class="token punctuation">.</span>getcwd<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token operator">/</span> <span class="token string">&quot;config.yaml&quot;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token keyword">not</span> path<span class="token punctuation">.</span>exists<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">            path <span class="token operator">=</span> Path<span class="token punctuation">(</span>os<span class="token punctuation">.</span>getcwd<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>parent <span class="token operator">/</span> <span class="token string">&quot;config.yaml&quot;</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>加载 YAML 后，系统依次解析 <code>title</code>、<code>summarization</code>、<code>memory</code>、<code>subagents</code>、<code>checkpointer</code> 等子配置，然后独立加载 <code>ExtensionsConfig</code>，最终通过 Pydantic 的 <code>model_validate</code> 完成校验。</p><p>配置采用<strong>单例缓存</strong>模式：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">_app_config<span class="token punctuation">:</span> AppConfig <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">get_app_config</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> AppConfig<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">global</span> _app_config</span>
<span class="line">    <span class="token keyword">if</span> _app_config <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        _app_config <span class="token operator">=</span> AppConfig<span class="token punctuation">.</span>from_file<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> _app_config</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行时可通过 <code>reload_app_config()</code> 热重载，或通过 <code>set_app_config()</code> 注入测试替身。</p><h2 id="_21-2-环境变量注入-var-name-语法" tabindex="-1"><a class="header-anchor" href="#_21-2-环境变量注入-var-name-语法"><span>21.2 环境变量注入：$VAR_NAME 语法</span></a></h2><p>DeerFlow 支持在 YAML 值中使用 <code>$</code> 前缀引用环境变量。<code>resolve_env_variables</code> 方法递归遍历整棵配置树，将所有以 <code>$</code> 开头的字符串替换为对应的环境变量值：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token decorator annotation punctuation">@classmethod</span></span>
<span class="line"><span class="token keyword">def</span> <span class="token function">resolve_env_variables</span><span class="token punctuation">(</span>cls<span class="token punctuation">,</span> config<span class="token punctuation">:</span> Any<span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> Any<span class="token punctuation">:</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token builtin">isinstance</span><span class="token punctuation">(</span>config<span class="token punctuation">,</span> <span class="token builtin">str</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">if</span> config<span class="token punctuation">.</span>startswith<span class="token punctuation">(</span><span class="token string">&quot;$&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">            env_value <span class="token operator">=</span> os<span class="token punctuation">.</span>getenv<span class="token punctuation">(</span>config<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">:</span><span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line">            <span class="token keyword">if</span> env_value <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">                <span class="token keyword">raise</span> ValueError<span class="token punctuation">(</span></span>
<span class="line">                    <span class="token string-interpolation"><span class="token string">f&quot;Environment variable </span><span class="token interpolation"><span class="token punctuation">{</span>config<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">:</span><span class="token format-spec">]</span><span class="token punctuation">}</span></span><span class="token string"> not found ...&quot;</span></span></span>
<span class="line">                <span class="token punctuation">)</span></span>
<span class="line">            <span class="token keyword">return</span> env_value</span>
<span class="line">        <span class="token keyword">return</span> config</span>
<span class="line">    <span class="token keyword">elif</span> <span class="token builtin">isinstance</span><span class="token punctuation">(</span>config<span class="token punctuation">,</span> <span class="token builtin">dict</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token punctuation">{</span>k<span class="token punctuation">:</span> cls<span class="token punctuation">.</span>resolve_env_variables<span class="token punctuation">(</span>v<span class="token punctuation">)</span> <span class="token keyword">for</span> k<span class="token punctuation">,</span> v <span class="token keyword">in</span> config<span class="token punctuation">.</span>items<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">elif</span> <span class="token builtin">isinstance</span><span class="token punctuation">(</span>config<span class="token punctuation">,</span> <span class="token builtin">list</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token punctuation">[</span>cls<span class="token punctuation">.</span>resolve_env_variables<span class="token punctuation">(</span>item<span class="token punctuation">)</span> <span class="token keyword">for</span> item <span class="token keyword">in</span> config<span class="token punctuation">]</span></span>
<span class="line">    <span class="token keyword">return</span> config</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>config.yaml</code> 中的实际写法：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">models</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> gpt<span class="token punctuation">-</span><span class="token number">4</span></span>
<span class="line">    <span class="token key atrule">use</span><span class="token punctuation">:</span> langchain_openai<span class="token punctuation">:</span>ChatOpenAI</span>
<span class="line">    <span class="token key atrule">model</span><span class="token punctuation">:</span> gpt<span class="token punctuation">-</span><span class="token number">4</span></span>
<span class="line">    <span class="token key atrule">api_key</span><span class="token punctuation">:</span> $OPENAI_API_KEY   <span class="token comment"># 运行时从环境变量读取</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：<code>config.yaml</code> 中的环境变量如果找不到会直接抛出异常；而 <code>extensions_config.json</code> 中找不到环境变量时，会静默替换为空字符串——两者行为有差异，这是设计上的考量。</p><h2 id="_21-3-config-yaml-全字段速查" tabindex="-1"><a class="header-anchor" href="#_21-3-config-yaml-全字段速查"><span>21.3 config.yaml 全字段速查</span></a></h2><p><code>config.yaml</code> 的顶层结构对应 <code>AppConfig</code> 的字段：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">models</span><span class="token punctuation">:</span>          <span class="token comment"># 模型列表，详见第 21 章</span></span>
<span class="line"><span class="token key atrule">tool_groups</span><span class="token punctuation">:</span>     <span class="token comment"># 工具分组（web, file:read, file:write, bash）</span></span>
<span class="line"><span class="token key atrule">tools</span><span class="token punctuation">:</span>           <span class="token comment"># 工具配置，每个工具指定 name/group/use 及额外参数</span></span>
<span class="line"><span class="token key atrule">sandbox</span><span class="token punctuation">:</span>         <span class="token comment"># 沙箱配置（use 字段指定 Provider 类）</span></span>
<span class="line"><span class="token key atrule">skills</span><span class="token punctuation">:</span>          <span class="token comment"># 技能目录配置（path, container_path）</span></span>
<span class="line"><span class="token key atrule">title</span><span class="token punctuation">:</span>           <span class="token comment"># 标题生成（enabled, max_words, max_chars, model_name）</span></span>
<span class="line"><span class="token key atrule">summarization</span><span class="token punctuation">:</span>   <span class="token comment"># 对话摘要（trigger, keep, trim_tokens_to_summarize）</span></span>
<span class="line"><span class="token key atrule">memory</span><span class="token punctuation">:</span>          <span class="token comment"># 全局记忆（storage_path, max_facts, injection_enabled）</span></span>
<span class="line"><span class="token key atrule">checkpointer</span><span class="token punctuation">:</span>    <span class="token comment"># 状态持久化（type: memory|sqlite|postgres）</span></span>
<span class="line"><span class="token key atrule">subagents</span><span class="token punctuation">:</span>       <span class="token comment"># 子 Agent 超时配置</span></span>
<span class="line"><span class="token key atrule">channels</span><span class="token punctuation">:</span>        <span class="token comment"># IM 渠道集成（feishu, slack, telegram）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>工具配置的基本结构：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token key atrule">tools</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> web_search</span>
<span class="line">    <span class="token key atrule">group</span><span class="token punctuation">:</span> web</span>
<span class="line">    <span class="token key atrule">use</span><span class="token punctuation">:</span> src.community.tavily.tools<span class="token punctuation">:</span>web_search_tool</span>
<span class="line">    <span class="token key atrule">max_results</span><span class="token punctuation">:</span> <span class="token number">5</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>use</code> 字段是 DeerFlow 配置体系的核心机制——它是一个 Python 类/变量路径，格式为 <code>module.path:ClassName</code>。系统通过 <code>resolve_class</code> 或 <code>resolve_variable</code> 在运行时动态导入。</p><h2 id="_21-4-extensions-config-json-mcp-服务器与技能状态" tabindex="-1"><a class="header-anchor" href="#_21-4-extensions-config-json-mcp-服务器与技能状态"><span>21.4 extensions_config.json：MCP 服务器与技能状态</span></a></h2><p><code>extensions_config.json</code> 是独立于 <code>config.yaml</code> 的 JSON 文件，管理两类扩展：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json" data-title="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">  <span class="token property">&quot;mcpServers&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;github&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;enabled&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;stdio&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;command&quot;</span><span class="token operator">:</span> <span class="token string">&quot;npx&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;args&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;-y&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;@modelcontextprotocol/server-github&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;env&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token property">&quot;GITHUB_TOKEN&quot;</span><span class="token operator">:</span> <span class="token string">&quot;$GITHUB_TOKEN&quot;</span></span>
<span class="line">      <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;description&quot;</span><span class="token operator">:</span> <span class="token string">&quot;GitHub MCP server&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;skills&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token property">&quot;my_custom_skill&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;enabled&quot;</span><span class="token operator">:</span> <span class="token boolean">false</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>文件定位逻辑与 <code>config.yaml</code> 类似，优先级为：</p><ol><li>参数传入；</li><li>环境变量 <code>DEER_FLOW_EXTENSIONS_CONFIG_PATH</code>；</li><li>当前目录或父目录的 <code>extensions_config.json</code>；</li><li>向后兼容：查找旧文件名 <code>mcp_config.json</code>。</li></ol><p>MCP 服务器支持三种传输类型：<code>stdio</code>（启动子进程）、<code>sse</code>（Server-Sent Events）和 <code>http</code>。对于 <code>sse</code>/<code>http</code> 类型，还可以配置 OAuth 认证：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">class</span> <span class="token class-name">McpServerConfig</span><span class="token punctuation">(</span>BaseModel<span class="token punctuation">)</span><span class="token punctuation">:</span></span>
<span class="line">    enabled<span class="token punctuation">:</span> <span class="token builtin">bool</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token builtin">type</span><span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span>default<span class="token operator">=</span><span class="token string">&quot;stdio&quot;</span><span class="token punctuation">)</span>       <span class="token comment"># stdio | sse | http</span></span>
<span class="line">    command<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>               <span class="token comment"># stdio 专用</span></span>
<span class="line">    args<span class="token punctuation">:</span> <span class="token builtin">list</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">list</span><span class="token punctuation">)</span></span>
<span class="line">    url<span class="token punctuation">:</span> <span class="token builtin">str</span> <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>                   <span class="token comment"># sse/http 专用</span></span>
<span class="line">    headers<span class="token punctuation">:</span> <span class="token builtin">dict</span><span class="token punctuation">[</span><span class="token builtin">str</span><span class="token punctuation">,</span> <span class="token builtin">str</span><span class="token punctuation">]</span> <span class="token operator">=</span> Field<span class="token punctuation">(</span>default_factory<span class="token operator">=</span><span class="token builtin">dict</span><span class="token punctuation">)</span></span>
<span class="line">    oauth<span class="token punctuation">:</span> McpOAuthConfig <span class="token operator">|</span> <span class="token boolean">None</span> <span class="token operator">=</span> <span class="token boolean">None</span>      <span class="token comment"># OAuth 令牌注入</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行时获取已启用的 MCP 服务器：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line">config <span class="token operator">=</span> get_extensions_config<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">enabled_servers <span class="token operator">=</span> config<span class="token punctuation">.</span>get_enabled_mcp_servers<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_21-5-skills-state-config" tabindex="-1"><a class="header-anchor" href="#_21-5-skills-state-config"><span>21.5 skills_state_config</span></a></h2><p>在 <code>extensions_config.json</code> 的 <code>skills</code> 字段中，可以控制各技能的启用状态。默认情况下，<code>public</code> 和 <code>custom</code> 类别的技能自动启用，只有在显式配置 <code>&quot;enabled&quot;: false</code> 时才会禁用：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py" data-title="py"><pre><code><span class="line"><span class="token keyword">def</span> <span class="token function">is_skill_enabled</span><span class="token punctuation">(</span>self<span class="token punctuation">,</span> skill_name<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">,</span> skill_category<span class="token punctuation">:</span> <span class="token builtin">str</span><span class="token punctuation">)</span> <span class="token operator">-</span><span class="token operator">&gt;</span> <span class="token builtin">bool</span><span class="token punctuation">:</span></span>
<span class="line">    skill_config <span class="token operator">=</span> self<span class="token punctuation">.</span>skills<span class="token punctuation">.</span>get<span class="token punctuation">(</span>skill_name<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> skill_config <span class="token keyword">is</span> <span class="token boolean">None</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> skill_category <span class="token keyword">in</span> <span class="token punctuation">(</span><span class="token string">&quot;public&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;custom&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> skill_config<span class="token punctuation">.</span>enabled</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_21-6-checkpointer-持久化配置" tabindex="-1"><a class="header-anchor" href="#_21-6-checkpointer-持久化配置"><span>21.6 Checkpointer 持久化配置</span></a></h2><p>DeerFlow 支持三种 Checkpointer 后端来持久化 LangGraph 的对话状态：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml" data-title="yml"><pre><code><span class="line"><span class="token comment"># 内存模式（默认，进程退出即丢失）</span></span>
<span class="line"><span class="token key atrule">checkpointer</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">type</span><span class="token punctuation">:</span> memory</span>
<span class="line"></span>
<span class="line"><span class="token comment"># SQLite 模式（本地文件持久化）</span></span>
<span class="line"><span class="token key atrule">checkpointer</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">type</span><span class="token punctuation">:</span> sqlite</span>
<span class="line">  <span class="token key atrule">connection_string</span><span class="token punctuation">:</span> checkpoints.db</span>
<span class="line"></span>
<span class="line"><span class="token comment"># PostgreSQL 模式（多进程/生产部署）</span></span>
<span class="line"><span class="token key atrule">checkpointer</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token key atrule">type</span><span class="token punctuation">:</span> postgres</span>
<span class="line">  <span class="token key atrule">connection_string</span><span class="token punctuation">:</span> postgresql<span class="token punctuation">:</span>//user<span class="token punctuation">:</span>password@localhost<span class="token punctuation">:</span>5432/deerflow</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用 SQLite 或 PostgreSQL 需要额外安装对应依赖包。</p><h2 id="小结" tabindex="-1"><a class="header-anchor" href="#小结"><span>小结</span></a></h2><p>DeerFlow 的配置体系遵循&quot;约定优于配置&quot;的原则：<code>config.yaml</code> 统管应用核心设置，<code>extensions_config.json</code> 独立管理扩展生态，环境变量通过 <code>$VAR</code> 语法安全注入敏感信息。所有配置均基于 Pydantic 模型进行校验，确保类型安全。<code>use</code> 字段的动态加载机制贯穿了模型、工具和沙箱三大子系统，是理解 DeerFlow 可扩展架构的关键。下一章我们将深入模型配置与适配的细节。</p><hr>`,41)),s("p",null,[n[1]||(n[1]=a("来源: ",-1)),s("a",r,[n[0]||(n[0]=a("DeerFlow Book",-1)),l(e)])])])}const v=p(u,[["render",d]]),b=JSON.parse('{"path":"/docs/Agent/DeerFlow/21-config-system.html","title":"第 21 章　配置体系全解","lang":"en-US","frontmatter":{},"headers":[{"level":2,"title":"21.1 配置加载流程","slug":"_21-1-配置加载流程","link":"#_21-1-配置加载流程","children":[]},{"level":2,"title":"21.2 环境变量注入：$VAR_NAME 语法","slug":"_21-2-环境变量注入-var-name-语法","link":"#_21-2-环境变量注入-var-name-语法","children":[]},{"level":2,"title":"21.3 config.yaml 全字段速查","slug":"_21-3-config-yaml-全字段速查","link":"#_21-3-config-yaml-全字段速查","children":[]},{"level":2,"title":"21.4 extensions_config.json：MCP 服务器与技能状态","slug":"_21-4-extensions-config-json-mcp-服务器与技能状态","link":"#_21-4-extensions-config-json-mcp-服务器与技能状态","children":[]},{"level":2,"title":"21.5 skills_state_config","slug":"_21-5-skills-state-config","link":"#_21-5-skills-state-config","children":[]},{"level":2,"title":"21.6 Checkpointer 持久化配置","slug":"_21-6-checkpointer-持久化配置","link":"#_21-6-checkpointer-持久化配置","children":[]},{"level":2,"title":"小结","slug":"小结","link":"#小结","children":[]}],"git":{},"filePathRelative":"docs/Agent/DeerFlow/21-config-system.md"}');export{v as comp,b as data};
